import React, { useEffect } from 'react';

const CanvasBackground = () => {
  const divRef = useRef(null);

  useEffect(() => {
    const div = divRef.current;
    let t = 0;

    const animate = () => {
      for (let x = 0; x <= 35; x++) {
        for (let y = 0; y <= 35; y++) {
          const r = Math.floor(128 + 64 * Math.cos((x * x - y * y) / 300 + t));
          const g = Math.floor(128 + 64 * Math.sin((x * x * Math.cos(t / 4) + y * y * Math.sin(t / 3)) / 300));
          const b = Math.floor(128 + 64 * Math.sin(5 * Math.sin(t / 9) + ((x - 100) * (x - 100) + (y - 100) * (y - 100)) / 1100));

          const divChild = document.createElement('div');
          divChild.style.width = '1px';
          divChild.style.height = '1px';
          divChild.style.backgroundColor = `rgb(${r - 100}, ${g - 100}, ${b - 100})`;
          divChild.style.position = 'absolute';
          divChild.style.left = `${x}px`;
          divChild.style.top = `${y}px`;
          div.appendChild(divChild);
        }
      }
      t = t + 0.005;
      window.requestAnimationFrame(animate);
    };

    animate();
  }, []);

  return <div ref={divRef} style={{ position: 'fixed', top: 0, left: 0, zIndex: -1, width: '100vw', height: '100vh' }} />;
};


export default CanvasBackground;
